// extract in chronological order, Otherwise deals created and deleted earlier will be left over
func extractDealProposalDetailedV3(ctx *extract.Ctx, res *extract.Res, head *common.ActorHead, st *market3.State) error {
	id, err := GenRegularHeadID(head.Head, head.Addr, head.Epoch)
	if err != nil {
		return fmt.Errorf("ge regular id: %w", err)
	}

	details := map[address.Address]*model.DealProposalDetail{}

	state, err := lmarket.Load(adt3.WrapStore(ctx.C, ctx.D.ActorStore(ctx.C)), head.Actor)
	if err != nil {
		return fmt.Errorf("failed to load market actor state: %w", err)
	}

	deals, err := market3.AsDealProposalArray(adt3.WrapStore(ctx.C, ctx.D.ActorStore(ctx.C)), st.Proposals)
	if err != nil {
		return fmt.Errorf("load deal proposal array: %w", err)
	}

	dealsStateArr, err := market3.AsDealStateArray(adt3.WrapStore(ctx.C, ctx.D.ActorStore(ctx.C)), st.States)
	if err != nil {
		return fmt.Errorf("load deal state array: %w", err)
	}

	var dealProposals []model.DealProposal

	nextID, err := state.NextID()
	if err != nil {
		return fmt.Errorf("get next ID failed: %w", err)
	}

	for idx := ctx.LatestDealID + 1; idx < int64(nextID); idx++ {
		out, found, err := deals.Get(abi.DealID(idx))
		if err != nil {
			return fmt.Errorf("get dealId %v failed: %v", idx, err)
		}

		if !found {
			continue
		}

		if _, ok := details[out.Provider]; !ok {
			details[out.Provider] = &model.DealProposalDetail{
				ActorStateExBasic: model.ActorStateExBasic{
					ID:    id,
					Path:  []cid.Cid{head.Head, st.Proposals},
					Addr:  out.Provider,
					Epoch: head.Epoch,
				},
			}
		}

		dealState, found, err := dealsStateArr.Get(abi.DealID(idx))
		if err != nil {
			return fmt.Errorf("load deal state failed: %w", err)
		}

		// no matter expire or slash
		unExpired := out.EndEpoch > head.Epoch || (found && dealState.SlashEpoch != -1)
		if unExpired && out.VerifiedDeal {
			details[out.Provider].Detail.VerifiedDealCount++
		} else if unExpired {
			details[out.Provider].Detail.UnVerifiedDealCount++
		} else if out.VerifiedDeal {
			details[out.Provider].Detail.VerifiedDealEndCount++
		} else {
			details[out.Provider].Detail.UnVerifiedDealEndCount++
		}

		providerID, err := extract.LookupID(ctx, out.Provider, head.TipSet)
		if err != nil {
			return fmt.Errorf("lookup ID for client %v at %v failed: %v", out.Provider, head.Epoch, err)
		}

		clientID, err := extract.LookupID(ctx, out.Client, head.TipSet)
		if err != nil {
			return fmt.Errorf("lookup ID for client %v at %v failed: %v", out.Client, head.Epoch, err)
		}

		dealProposals = append(dealProposals, model.DealProposal{
			ID:           idx,
			Epoch:        head.Epoch,
			ProviderID:   providerID,
			ClientID:     clientID,
			DealProposal: *out,
		})
	}

	for i := range details {
		res.Docs = append(res.Docs, details[i])
	}

	for i := range dealProposals {
		res.Docs = append(res.Docs, &dealProposals[i])
	}
	return nil
}
